        let utilizadorLogado = null;

        // ============================
        // INICIALIZAÇÃO
        // ============================
        document.addEventListener('DOMContentLoaded', () => {
            carregarUtilizador();
        });

        function carregarUtilizador() {
            const usuarioStr = localStorage.getItem('usuarioLogado');
            if (!usuarioStr) {
                window.location.href = 'auth.html';
                return;
            }
            utilizadorLogado = JSON.parse(usuarioStr);

            // Se for capitão, redirecionar para o dashboard correcto
            if (utilizadorLogado.tipo === 'capitao') {
                window.location.href = 'dashboard-capitao.html';
                return;
            }

            // Actualizar sidebar
            const iniciais = utilizadorLogado.nome.split(' ').map(n => n[0]).join('').substring(0,2).toUpperCase();
            document.getElementById('sidebarAvatar').textContent = iniciais;
            document.getElementById('sidebarNome').textContent = utilizadorLogado.nome;
            document.getElementById('dashboardTitulo').textContent = `Bem-vindo, ${utilizadorLogado.nome.split(' ')[0]}! 👋`;

            // Carregar dados iniciais
            carregarDadosPerfil();
            atualizarStats();
            carregarProximasReservas();
            atualizarContadoresPartilha();

            // Navegação por hash
            const hash = window.location.hash.replace('#','');
            if (hash) setTimeout(() => navegarSecao(hash), 100);
        }

        // ============================
        // STATS
        // ============================
        function atualizarStats() {
            if (!utilizadorLogado) return;
            const reservas = JSON.parse(localStorage.getItem('reservasPendentes') || '[]');
            const minhas = reservas.filter(r => r.clienteEmail === utilizadorLogado.email);
            const ativas = minhas.filter(r => r.status === 'pendente' || r.status === 'confirmada').length;
            const concluidas = minhas.filter(r => r.status === 'concluida').length;
            document.getElementById('statReservasAtivas').textContent = ativas;
            document.getElementById('statSaidasRealizadas').textContent = concluidas;
        }

        // ============================
        // PRÓXIMAS RESERVAS (dashboard)
        // ============================
        function carregarProximasReservas() {
            if (!utilizadorLogado) return;
            const reservas = JSON.parse(localStorage.getItem('reservasPendentes') || '[]');
            const proximas = reservas
                .filter(r => r.clienteEmail === utilizadorLogado.email && (r.status === 'pendente' || r.status === 'confirmada'))
                .sort((a,b) => new Date(a.dataPedido) - new Date(b.dataPedido))
                .slice(0,3);

            const container = document.getElementById('proximasReservasContainer');
            if (!container) return;

            if (proximas.length === 0) {
                container.innerHTML = `
                    <div class="estado-vazio">
                        <i class="fas fa-calendar-times estado-vazio-icon"></i>
                        <h3 class="estado-vazio-titulo">Nenhuma Reserva Agendada</h3>
                        <p class="estado-vazio-texto">Explore as melhores experiências de pesca no Algarve!</p>
                        <a href="explorar.html" class="btn btn-primario"><i class="fas fa-search"></i> Explorar Saídas</a>
                    </div>`;
                return;
            }

            container.innerHTML = `<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:1rem;">
                ${proximas.map(r => buildReservaCard(r)).join('')}
            </div>`;
        }

        // ============================
        // LISTA COMPLETA DE RESERVAS
        // ============================
        function carregarMinhasReservas() {
            if (!utilizadorLogado) return;
            const reservas = JSON.parse(localStorage.getItem('reservasPendentes') || '[]');
            const minhas = reservas.filter(r => r.clienteEmail === utilizadorLogado.email);
            const container = document.getElementById('listaReservasCliente');
            if (!container) return;

            if (minhas.length === 0) {
                container.innerHTML = `
                    <div class="estado-vazio">
                        <i class="fas fa-ticket-alt estado-vazio-icon"></i>
                        <h3 class="estado-vazio-titulo">Sem Reservas</h3>
                        <p class="estado-vazio-texto">Ainda não fez nenhuma reserva.<br>Explore as saídas disponíveis!</p>
                        <a href="explorar.html" class="btn btn-primario" style="margin-top:1.5rem;">
                            <i class="fas fa-search"></i> Explorar Saídas
                        </a>
                    </div>`;
                return;
            }

            const sorted = minhas.sort((a,b) => new Date(b.dataPedido) - new Date(a.dataPedido));
            container.innerHTML = `<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(340px,1fr));gap:1.5rem;padding:1rem 0;">
                ${sorted.map(r => buildReservaCard(r, true)).join('')}
            </div>`;
        }

        function buildReservaCard(r, showCancel = false) {
            const corStatus  = { pendente:'#F59E0B', confirmada:'#10B981', cancelada:'#EF4444', concluida:'#6B7280' };
            const iconStatus = { pendente:'fa-clock', confirmada:'fa-check-circle', cancelada:'fa-times-circle', concluida:'fa-flag-checkered' };
            const lblStatus  = { pendente:'Pendente', confirmada:'Confirmada', cancelada:'Cancelada', concluida:'Concluída' };
            const st  = r.status || 'pendente';
            const cor = corStatus[st]  || '#6B7280';
            const ic  = iconStatus[st] || 'fa-circle';
            const lbl = lblStatus[st]  || st;
            const dataFmt = r.saidaData
                ? new Date(r.saidaData).toLocaleDateString('pt-PT',{day:'2-digit',month:'2-digit',year:'numeric'})
                : '—';

            return `
            <div class="reserva-card">
                <div class="reserva-card-header">
                    <div style="color:white;">
                        <div style="font-weight:700;font-size:1rem;">${r.saidaTitulo || 'Saída'}</div>
                        <div style="font-size:0.8rem;opacity:0.8;">${dataFmt}</div>
                    </div>
                    <span class="badge-status badge-${st}">
                        <i class="fas ${ic}"></i> ${lbl}
                    </span>
                </div>
                <div class="reserva-card-body">
                    <div style="display:flex;gap:1rem;flex-wrap:wrap;font-size:0.85rem;color:#6B7280;margin-bottom:0.75rem;">
                        <span><i class="fas fa-ship"></i> ${r.barcoNome || '—'}</span>
                        <span><i class="fas fa-user-tie"></i> ${r.capitaoNome || '—'}</span>
                        <span><i class="fas fa-map-marker-alt"></i> ${r.saidaPorto || '—'}</span>
                    </div>
                    <div style="display:flex;justify-content:space-between;align-items:center;background:#F9FAFB;border-radius:8px;padding:0.75rem;">
                        <div>
                            <div style="font-size:0.8rem;color:#6B7280;">Pessoas / Total</div>
                            <div style="font-weight:700;color:#0A1628;">${(r.numPessoas || r.cliente?.numPescadores || 1)} pessoa(s) · ${r.totalPagar !== undefined && r.totalPagar !== null ? ('€' + r.totalPagar) : '—'}</div>
                        </div>
                        <a href="detalhe-saida.html?id=${r.saidaId}" style="color:var(--cor-secundaria);font-size:0.85rem;font-weight:600;">
                            Ver Saída <i class="fas fa-arrow-right"></i>
                        </a>
                    </div>
                    ${showCancel && r.status === 'pendente' ? `
                    <button onclick="cancelarReserva(${r.id})" style="width:100%;margin-top:0.75rem;padding:0.5rem;background:transparent;border:1px solid #EF4444;color:#EF4444;border-radius:6px;cursor:pointer;font-size:0.85rem;">
                        <i class="fas fa-times"></i> Cancelar Reserva
                    </button>` : ''}
                </div>
            </div>`;
        }

        // ============================
        // CANCELAR RESERVA
        // ============================
        function cancelarReserva(id) {
            if (!confirm('Tem a certeza que deseja cancelar esta reserva?')) return;
            const reservas = JSON.parse(localStorage.getItem('reservasPendentes') || '[]');
            const idx = reservas.findIndex(r => r.id === id);
            if (idx !== -1) {
                // Devolver vaga
                const saidas = JSON.parse(localStorage.getItem('saidasData') || '[]');
                const saidaIdx = saidas.findIndex(s => String(s.id) === String(reservas[idx].saidaId));
                if (saidaIdx !== -1 && saidas[saidaIdx].vagasOcupadas > 0) {
                    saidas[saidaIdx].vagasOcupadas -= (reservas[idx].numPessoas || 1);
                    if (saidas[saidaIdx].vagasOcupadas < 0) saidas[saidaIdx].vagasOcupadas = 0;
                    localStorage.setItem('saidasData', JSON.stringify(saidas));
                }
                reservas[idx].status = 'cancelada';
                localStorage.setItem('reservasPendentes', JSON.stringify(reservas));
                if (window.mostrarToast) mostrarToast('Reserva cancelada.', 'aviso');
                carregarMinhasReservas();
                atualizarStats();
            }
        }

        // ============================
        // PERFIL
        // ============================
        function carregarDadosPerfil() {
            if (!utilizadorLogado) return;
            document.getElementById('perfilNome').value        = utilizadorLogado.nome          || '';
            document.getElementById('perfilEmail').value       = utilizadorLogado.email         || '';
            document.getElementById('perfilTelefone').value    = utilizadorLogado.telefone      || '';
            document.getElementById('perfilMorada').value      = utilizadorLogado.morada        || '';
            document.getElementById('perfilCidade').value      = utilizadorLogado.cidade        || '';
            document.getElementById('perfilCodigoPostal').value= utilizadorLogado.codigoPostal  || '';
            document.getElementById('perfilNIF').value         = utilizadorLogado.nif           || '';
            document.getElementById('perfilPasswordAtual').value  = '';
            document.getElementById('perfilNovaPassword').value   = '';
            document.getElementById('perfilConfirmarPassword').value = '';
        }

        document.getElementById('formEditarPerfil').addEventListener('submit', (e) => {
            e.preventDefault();
            const nome          = document.getElementById('perfilNome').value.trim();
            const telefone      = document.getElementById('perfilTelefone').value.trim();
            const morada        = document.getElementById('perfilMorada').value.trim();
            const cidade        = document.getElementById('perfilCidade').value.trim();
            const codigoPostal  = document.getElementById('perfilCodigoPostal').value.trim();
            const nif           = document.getElementById('perfilNIF').value.trim();
            const passwordAtual = document.getElementById('perfilPasswordAtual').value;
            const novaPassword  = document.getElementById('perfilNovaPassword').value;
            const confirmarPwd  = document.getElementById('perfilConfirmarPassword').value;

            if (!nome) { mostrarToast('❌ Nome é obrigatório!', 'erro'); return; }

            if (passwordAtual || novaPassword || confirmarPwd) {
                if (!passwordAtual) { mostrarToast('❌ Digite a password atual!', 'erro'); return; }
                if (passwordAtual !== utilizadorLogado.password) { mostrarToast('❌ Password atual incorreta!', 'erro'); return; }
                if (novaPassword !== confirmarPwd) { mostrarToast('❌ As novas passwords não coincidem!', 'erro'); return; }
                if (novaPassword.length < 6) { mostrarToast('❌ Mínimo 6 caracteres!', 'erro'); return; }
            }

            let utilizadores = JSON.parse(localStorage.getItem('utilizadores') || '[]');
            const index = utilizadores.findIndex(u => u.email === utilizadorLogado.email);

            if (index !== -1) {
                utilizadores[index].nome        = nome;
                utilizadores[index].telefone    = telefone;
                utilizadores[index].morada      = morada;
                utilizadores[index].cidade      = cidade;
                utilizadores[index].codigoPostal= codigoPostal;
                utilizadores[index].nif         = nif;
                if (novaPassword) utilizadores[index].password = novaPassword;
                utilizadores[index].dataAtualizacao = new Date().toISOString();
                localStorage.setItem('utilizadores', JSON.stringify(utilizadores));
                utilizadorLogado = utilizadores[index];
                localStorage.setItem('usuarioLogado', JSON.stringify(utilizadorLogado));
                mostrarToast('✅ Perfil atualizado com sucesso!', 'sucesso');
                carregarUtilizador();
                carregarDadosPerfil();
            } else {
                mostrarToast('❌ Erro ao atualizar perfil!', 'erro');
            }
        });

        // ============================
        // NAVEGAÇÃO SIDEBAR
        // ============================
        const menuItems = document.querySelectorAll('.sidebar-menu-item');
        const sections  = document.querySelectorAll('.dashboard-secao-wrapper');

        function navegarSecao(nome) {
            menuItems.forEach(i => i.classList.remove('ativo'));
            sections.forEach(s => s.classList.add('oculto'));
            const item = document.querySelector(`[data-section="${nome}"]`);
            if (item) item.classList.add('ativo');
            const sec = document.getElementById('secao-' + nome);
            if (sec) sec.classList.remove('oculto');
            if (nome === 'reservas') carregarMinhasReservas();
            if (nome === 'partilhadas') carregarSaidasPartilhadas();
        }

        menuItems.forEach(item => {
            item.addEventListener('click', e => {
                e.preventDefault();
                navegarSecao(item.dataset.section);
            });
        });

        document.getElementById('sidebarToggle').addEventListener('click', () => {
            document.getElementById('sidebar').classList.toggle('ativo');
        });

        // ============================
        // LOGOUT
        // ============================

        // ============================
        // CONTADORES DASHBOARD PRINCIPAL
        // ============================
        function atualizarContadoresPartilha() {
            try {
                const saidas = JSON.parse(localStorage.getItem('saidasData') || '[]');
                const nBarcos = saidas.filter(s => s.status === 'ativa' && s.permitePartilha && !s.partilhada).length;
                const nEmCurso = saidas.filter(s => {
                    if (s.status !== 'ativa' || !s.partilhada) return false;
                    const total = s.vagasDisponiveis || s.maxPartilha || s.lotacao || 0;
                    const livres = Math.max(0, total - (s.vagasOcupadas || 0));
                    return livres > 0;
                }).length;
                const elBarcos = document.getElementById('dashCountBarcos');
                const elCurso = document.getElementById('dashCountEmCurso');
                if (elBarcos) elBarcos.textContent = nBarcos;
                if (elCurso) elCurso.textContent = nEmCurso;
            } catch(e) {}
        }

        function logout() {
            if (confirm('Tem a certeza que deseja sair?')) {
                localStorage.removeItem('usuarioLogado');
                window.location.href = 'index.html';
            }
        }


        // ============================
        // SAÍDAS PARTILHADAS
        // ============================
        let tabPartilhaAtiva = 'barcos';

        function mudarTabPartilha(tab) {
            tabPartilhaAtiva = tab;
            document.getElementById('tabBarcos').classList.toggle('ativa', tab === 'barcos');
            document.getElementById('tabEmCurso').classList.toggle('ativa', tab === 'emcurso');
            document.getElementById('gridBarcosPartilha').style.display = tab === 'barcos' ? 'grid' : 'none';
            document.getElementById('gridSaidasEmCurso').style.display = tab === 'emcurso' ? 'grid' : 'none';
        }

        function carregarSaidasPartilhadas() {
            const zona = document.getElementById('filtroPartilhaZona')?.value || '';
            const tipo = document.getElementById('filtroPartilhaTipo')?.value || '';
            const todasSaidas = JSON.parse(localStorage.getItem('saidasData') || '[]');
            const placeholderImg = 'https://images.unsplash.com/photo-1559827260-dc66d52bef19?w=600&h=400&fit=crop';

            // Filtro base por zona e tipo
            function passaFiltros(saida) {
                if (zona) {
                    const loc = (saida.localizacao || '').toLowerCase();
                    const z = zona.toLowerCase();
                    if (!loc.includes(z) && !z.includes(loc)) return false;
                }
                if (tipo && !(saida.tipos || []).includes(tipo)) return false;
                return true;
            }

            // ---- TAB 1: BARCOS DISPONÍVEIS ----
            // Barcos com permitePartilha=true, status ativa, e que ainda NÃO estão em curso partilhada
            // (ou seja: o capitão aceita partilha mas ainda não há reserva que a ativou)
            const barcosDisponiveis = todasSaidas.filter(s =>
                s.status === 'ativa' &&
                s.permitePartilha === true &&
                !s.partilhada &&
                passaFiltros(s)
            );

            // ---- TAB 2: SAÍDAS EM CURSO (partilhadas ativas com vagas) ----
            const saidasEmCurso = todasSaidas.filter(s =>
                s.status === 'ativa' &&
                s.partilhada === true &&
                passaFiltros(s)
            ).map(s => {
                const vagasTotal = s.vagasDisponiveis || s.maxPartilha || s.lotacao || 0;
                const vagasOcup = s.vagasOcupadas || 0;
                const vagasLivres = Math.max(0, vagasTotal - vagasOcup);
                return { ...s, vagasLivresPartilha: vagasLivres };
            }).filter(s => s.vagasLivresPartilha > 0);

            // Actualizar contadores
            document.getElementById('countBarcos').textContent = barcosDisponiveis.length;
            document.getElementById('countEmCurso').textContent = saidasEmCurso.length;

            // Renderizar TAB 1: Barcos Disponíveis
            const gridBarcos = document.getElementById('gridBarcosPartilha');
            if (barcosDisponiveis.length === 0) {
                gridBarcos.innerHTML = `
                    <div class="partilhadas-vazia" style="grid-column:1/-1;">
                        <i class="fas fa-ship"></i>
                        <strong style="display:block;color:rgba(255,255,255,0.7);font-size:1rem;margin-bottom:0.5rem;">Sem barcos disponíveis</strong>
                        <p>Não há barcos com partilha disponível${zona ? ' nesta zona' : ''}${tipo ? ' deste tipo' : ''}.</p>
                    </div>`;
            } else {
                gridBarcos.innerHTML = barcosDisponiveis.map(saida => {
                    const img = saida.imagem || placeholderImg;
                    const tipos = (saida.tipos || []).slice(0,2).map(t => formatarTipoPescaPartilha(t)).join(' · ') || '—';
                    const maxP = saida.maxPartilha || saida.lotacao || '?';
                    return `
                    <div class="barco-partilha-card">
                        <img src="${img}" alt="${saida.barco}" class="barco-partilha-img" onerror="this.src='${placeholderImg}'">
                        <div class="barco-partilha-info">
                            <div class="barco-partilha-badge">🤝 Aceita Partilha</div>
                            <div class="barco-partilha-nome">${saida.barco}</div>
                            <div class="barco-partilha-meta">
                                <span><i class="fas fa-user-tie"></i> Capitão ${saida.capitao}</span>
                                <span><i class="fas fa-map-marker-alt"></i> ${saida.localizacao}</span>
                                <span><i class="fas fa-clock"></i> ${saida.duracao ? saida.duracao + 'h' : 'A combinar'}</span>
                                <span><i class="fas fa-users"></i> Até ${maxP} pescadores</span>
                            </div>
                            <div style="margin:0.5rem 0;">
                                ${(saida.tipos||[]).slice(0,3).map(t=>`<span style="background:rgba(255,143,0,0.15);color:#FFB74D;font-size:0.75rem;padding:0.2rem 0.5rem;border-radius:12px;margin-right:0.3rem;">${formatarTipoPescaPartilha(t)}</span>`).join('')}
                            </div>
                            <div style="display:flex;justify-content:space-between;align-items:center;margin-top:0.8rem;">
                                <div style="color:#FFB74D;font-size:1.1rem;font-weight:700;">€${saida.precoPartilhado || saida.preco}<span style="font-size:0.75rem;font-weight:400;color:rgba(255,255,255,0.6);">/pessoa</span></div>
                                <a href="detalhe-saida.html?id=${saida.id}" style="background:linear-gradient(135deg,#FF8F00,#FFB74D);color:#fff;border:none;padding:0.5rem 1rem;border-radius:8px;font-weight:700;font-size:0.85rem;text-decoration:none;cursor:pointer;">
                                    <i class="fas fa-paper-plane"></i> Reservar
                                </a>
                            </div>
                        </div>
                    </div>`;
                }).join('');
            }

            // Renderizar TAB 2: Saídas Em Curso
            const gridEmCurso = document.getElementById('gridSaidasEmCurso');
            if (saidasEmCurso.length === 0) {
                gridEmCurso.innerHTML = `
                    <div class="partilhadas-vazia" style="grid-column:1/-1;">
                        <i class="fas fa-anchor"></i>
                        <strong style="display:block;color:rgba(255,255,255,0.7);font-size:1rem;margin-bottom:0.5rem;">Nenhuma saída com vagas</strong>
                        <p>Não há saídas em curso com lugares disponíveis${zona ? ' nesta zona' : ''}.</p>
                    </div>`;
            } else {
                gridEmCurso.innerHTML = saidasEmCurso.map(saida => {
                    const img = saida.imagem || placeholderImg;
                    const vagasTotal = saida.vagasDisponiveis || saida.maxPartilha || saida.lotacao || 0;
                    const vagasOcup = saida.vagasOcupadas || 0;
                    const vagasLivres = saida.vagasLivresPartilha;
                    const pct = vagasTotal > 0 ? Math.round((vagasOcup / vagasTotal) * 100) : 0;
                    const classBarra = pct >= 90 ? 'cheio' : pct >= 60 ? 'quase-cheio' : '';
                    return `
                    <div class="saida-partilhada-card">
                        <div class="saida-partilhada-header">🤝 SAÍDA PARTILHADA — ${vagasLivres} lugar(es) disponíve${vagasLivres === 1 ? 'l' : 'is'}!</div>
                        <img src="${img}" alt="${saida.titulo}" class="saida-partilhada-img" onerror="this.src='${placeholderImg}'">
                        <div class="saida-partilhada-info">
                            <div class="saida-partilhada-titulo">${saida.titulo}</div>
                            <div style="font-size:0.85rem;color:rgba(255,255,255,0.7);margin-bottom:0.75rem;">
                                <span><i class="fas fa-user-tie"></i> ${saida.capitao}</span> ·
                                <span><i class="fas fa-ship"></i> ${saida.barco}</span>
