    // ── Sistema de Feedback / Avaliação ──
    let _feedbackReservaId = null;
    let _feedbackSaidaId = null;
    let _feedbackNota = 0;
    let _feedbackFotos = [];

    function abrirModalFeedback(reservaId, saidaId, saidaTitulo) {
        _feedbackReservaId = reservaId;
        _feedbackSaidaId = saidaId;
        _feedbackNota = 0;
        _feedbackFotos = [];
        document.getElementById('feedbackSaidaTitulo').textContent = saidaTitulo || 'Saída de Pesca';
        document.getElementById('feedbackComentario').value = '';
        document.getElementById('fotosPreview').innerHTML = '';
        document.getElementById('feedbackLabel').textContent = 'Clique para avaliar';
        document.querySelectorAll('.feedback-star').forEach(s => s.classList.remove('ativa'));
        document.getElementById('modalFeedback').classList.add('aberto');
    }

    function fecharModalFeedback() {
        document.getElementById('modalFeedback').classList.remove('aberto');
    }

    // Stars interativas
    document.querySelectorAll('.feedback-star').forEach(star => {
        star.addEventListener('click', function() {
            _feedbackNota = parseInt(this.dataset.val);
            const labels = ['','😞 Mau','😐 Razoável','🙂 Bom','😊 Muito Bom','🤩 Excelente!'];
            document.getElementById('feedbackLabel').textContent = labels[_feedbackNota];
            document.querySelectorAll('.feedback-star').forEach(s => {
                s.classList.toggle('ativa', parseInt(s.dataset.val) <= _feedbackNota);
            });
        });
        star.addEventListener('mouseover', function() {
            const v = parseInt(this.dataset.val);
            document.querySelectorAll('.feedback-star').forEach(s => {
                s.style.color = parseInt(s.dataset.val) <= v ? '#F59E0B' : '#D1D5DB';
            });
        });
        star.addEventListener('mouseout', function() {
            document.querySelectorAll('.feedback-star').forEach(s => {
                s.style.color = parseInt(s.dataset.val) <= _feedbackNota ? '#F59E0B' : '#D1D5DB';
            });
        });
    });

    function previewFotos(input) {
        const preview = document.getElementById('fotosPreview');
        _feedbackFotos = [];
        Array.from(input.files).forEach(file => {
            const reader = new FileReader();
            reader.onload = e => {
                _feedbackFotos.push(e.target.result);
                const img = document.createElement('img');
                img.src = e.target.result;
                img.className = 'foto-thumb';
                preview.appendChild(img);
            };
            reader.readAsDataURL(file);
        });
    }

    function submeterFeedback() {
        if (_feedbackNota === 0) {
            if (window.mostrarToast) mostrarToast('⚠️ Selecione uma avaliação (1-5 estrelas)', 'erro');
            return;
        }
        const comentario = document.getElementById('feedbackComentario').value.trim();
        const usuario = JSON.parse(localStorage.getItem('usuarioLogado') || 'null');

        // Guardar avaliação
        const avaliacoes = JSON.parse(localStorage.getItem('avaliacoesSaidas') || '[]');
        avaliacoes.push({
            id: Date.now(),
            reservaId: _feedbackReservaId,
            saidaId: _feedbackSaidaId,
            clienteEmail: usuario?.email || '',
            clienteNome: usuario?.nome || '',
            nota: _feedbackNota,
            comentario,
            fotos: _feedbackFotos,
            data: new Date().toISOString()
        });
        localStorage.setItem('avaliacoesSaidas', JSON.stringify(avaliacoes));

        // Atualizar rating médio da saída
        const saidas = JSON.parse(localStorage.getItem('saidasData') || '[]');
        const idx = saidas.findIndex(s => String(s.id) === String(_feedbackSaidaId));
        if (idx !== -1) {
            const avsDestaSaida = avaliacoes.filter(a => String(a.saidaId) === String(_feedbackSaidaId));
            const media = avsDestaSaida.reduce((acc, a) => acc + a.nota, 0) / avsDestaSaida.length;
            saidas[idx].rating = Math.round(media * 10) / 10;
            saidas[idx].avaliacoes = avsDestaSaida.length;
            localStorage.setItem('saidasData', JSON.stringify(saidas));
        }

        // Marcar reserva como avaliada
        const reservas = JSON.parse(localStorage.getItem('reservasPendentes') || '[]');
        const rIdx = reservas.findIndex(r => String(r.id) === String(_feedbackReservaId));
        if (rIdx !== -1) { reservas[rIdx].avaliada = true; localStorage.setItem('reservasPendentes', JSON.stringify(reservas)); }

        fecharModalFeedback();
        if (window.mostrarToast) mostrarToast('⭐ Obrigado pela sua avaliação!', 'sucesso');
        setTimeout(() => location.reload(), 1500);
    }




