        // 📊 FUNÇÃO PARA CARREGAR ESTATÍSTICAS DO CAPITÃO
        function carregarEstatisticas() {
            const usuarioStr = localStorage.getItem('usuarioLogado');
            if (!usuarioStr) return;

            const capitao = JSON.parse(usuarioStr);
            const emailCapitao = capitao.email;

            // Carregar barcos do capitão
            const todosBarcos = JSON.parse(localStorage.getItem('barcos') || '[]');
            const barcosCapitao = todosBarcos.filter(b => b.capitaoEmail === emailCapitao);
            document.getElementById('totalBarcos').textContent = barcosCapitao.length;

            // Carregar saídas agendadas (apenas futuras)
            const todasSaidas = JSON.parse(localStorage.getItem('saidasData') || '[]');
            const hoje = new Date();
            // Contar todas as saídas ativas do capitão (já não têm data fixa)
            const saidasCapitao = todasSaidas.filter(s => s.capitaoEmail === emailCapitao && s.status !== 'cancelada');
            document.getElementById('totalSaidas').textContent = saidasCapitao.length;

            // Carregar contactos/reservas pendentes este mês
            const reservas = JSON.parse(localStorage.getItem('reservasPendentes') || '[]');
            const primeiroDiaMes = new Date(hoje.getFullYear(), hoje.getMonth(), 1);
            const reservasCapitao = reservas.filter(r => r.capitaoEmail === emailCapitao);
            const contactosMes = reservasCapitao.filter(r => {
                const dataReserva = new Date(r.dataPedido || r.dataCriacao || r.data);
                return dataReserva >= primeiroDiaMes;
            });
            document.getElementById('totalContactos').textContent = contactosMes.length;

            // Atualizar badge de pedidos pendentes na sidebar
            const pendentesCount = reservasCapitao.filter(r => r.status === 'pendente').length;
            const badgePendentes = document.querySelector('[data-section="reservas"] .badge, #badgePendentes');
            if (badgePendentes) badgePendentes.textContent = pendentesCount;

            // Calcular avaliação média
            const avaliacoes = JSON.parse(localStorage.getItem('avaliacoes') || '[]');
            const avaliacoesCapitao = avaliacoes.filter(a => a.capitaoEmail === emailCapitao);
            if (avaliacoesCapitao.length > 0) {
                const soma = avaliacoesCapitao.reduce((acc, a) => acc + (a.nota || 0), 0);
                const media = (soma / avaliacoesCapitao.length).toFixed(1);
                document.getElementById('avaliacaoMedia').textContent = media;
            } else {
                document.getElementById('avaliacaoMedia').textContent = '--';
            }
            document.getElementById('totalAvaliacoes').innerHTML = `<i class="fas fa-star"></i> ${avaliacoesCapitao.length} avaliações`;
        }

        // 🧹 FUNÇÃO PARA LIMPAR BARCOS MOCK/TESTE
        function limparBarcosMock() {
            const barcos = JSON.parse(localStorage.getItem('barcos') || '[]');
            const barcosReais = barcos.filter(barco => {
                const nomeTeste = (barco.nome || '').toLowerCase();
                const matriculaTeste = (barco.matricula || '').toLowerCase();

                // Remover barcos com nomes/dados de teste
                return !nomeTeste.includes('teste') &&
                       !nomeTeste.includes('test') &&
                       !nomeTeste.includes('mar azul') && // Exemplo mock
                       !nomeTeste.includes('oceano bravo') && // Exemplo mock
                       !matriculaTeste.includes('teste') &&
                       !matriculaTeste.includes('test') &&
                       barco.nome && // Deve ter nome
                       barco.tipo && // Deve ter tipo
                       barco.comprimento; // Deve ter comprimento
            });

            if (barcos.length !== barcosReais.length) {
                console.log(`🧹 Limpeza: ${barcos.length - barcosReais.length} barcos mock removidos`);
                localStorage.setItem('barcos', JSON.stringify(barcosReais));
            }
        }

