            if (sidebarNome) sidebarNome.textContent = capitao.nome;
            if (sidebarAvatar) {
                const initials = capitao.nome.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();
                sidebarAvatar.textContent = initials;
            }

            mostrarToast('Perfil atualizado com sucesso!', 'sucesso');
        });

        // ============================================
        // CARREGAR RESERVAS
        // ============================================
        // ════════════════════════════════════════════════
        // SISTEMA DE RESERVAS – CAPITÃO (novo)
        // ════════════════════════════════════════════════
        function carregarReservas() {
            const utilizadorLogado = JSON.parse(localStorage.getItem('usuarioLogado') || 'null');
            if (!utilizadorLogado) return;

            const reservas = JSON.parse(localStorage.getItem('reservasPendentes') || '[]');
            const minhas = reservas.filter(r => r.capitaoEmail === utilizadorLogado.email);
            const pendentes = minhas.filter(r => r.status === 'pendente');
            const confirmadas = minhas.filter(r => r.status === 'confirmada');
            const todas = minhas;

            const container = document.getElementById('container-reservas');
            const estadoVazio = document.getElementById('estado-vazio-reservas');

            if (!container) return;

            if (todas.length === 0) {
                container.style.display = 'none';
                if (estadoVazio) estadoVazio.style.display = 'flex';
                return;
            }

            if (estadoVazio) estadoVazio.style.display = 'none';
            container.style.display = 'block';

            // Tabs pendentes / confirmadas / todas
            container.innerHTML = `
                <div style="display:flex;gap:0.5rem;margin-bottom:1.5rem;flex-wrap:wrap;">
                    <button onclick="filtrarReservasCapitao('pendente',this)" class="btn-tab-res ativo" style="padding:0.5rem 1.2rem;border-radius:20px;border:2px solid #F59E0B;background:#FEF3C7;color:#92400E;font-weight:600;cursor:pointer;font-size:0.85rem;">
                        ⏳ Pendentes (${pendentes.length})
                    </button>
                    <button onclick="filtrarReservasCapitao('confirmada',this)" class="btn-tab-res" style="padding:0.5rem 1.2rem;border-radius:20px;border:2px solid #10B981;background:transparent;color:#10B981;font-weight:600;cursor:pointer;font-size:0.85rem;">
                        ✅ Confirmadas (${confirmadas.length})
                    </button>
                    <button onclick="filtrarReservasCapitao('todas',this)" class="btn-tab-res" style="padding:0.5rem 1.2rem;border-radius:20px;border:2px solid #6B7280;background:transparent;color:#6B7280;font-weight:600;cursor:pointer;font-size:0.85rem;">
                        📋 Todas (${todas.length})
                    </button>
                </div>
                <div id="listaReservasCapitao"></div>
            `;

            // Guardar referência para filtragem
            window._todasReservasCapitao = todas;
            renderizarReservasCapitao(pendentes);
        }

        function filtrarReservasCapitao(filtro, btn) {
            // Estilo dos tabs
            document.querySelectorAll('.btn-tab-res').forEach(b => {
                b.style.background = 'transparent';
                b.style.opacity = '0.6';
            });
            btn.style.background = filtro === 'pendente' ? '#FEF3C7' : filtro === 'confirmada' ? '#D1FAE5' : '#F3F4F6';
            btn.style.opacity = '1';

            const todas = window._todasReservasCapitao || [];
            const lista = filtro === 'todas' ? todas : todas.filter(r => r.status === filtro);
            renderizarReservasCapitao(lista);
        }

        function renderizarReservasCapitao(lista) {
            const div = document.getElementById('listaReservasCapitao');
            if (!div) return;

            if (lista.length === 0) {
                div.innerHTML = '<p style="color:#9CA3AF;text-align:center;padding:2rem;">Sem reservas neste estado.</p>';
                return;
            }

            const corStatus = { pendente:'#F59E0B', confirmada:'#10B981', cancelada:'#EF4444' };
            const lblStatus = { pendente:'Pendente', confirmada:'Confirmada', cancelada:'Cancelada' };

            div.innerHTML = lista.sort((a,b) => new Date(b.dataPedido) - new Date(a.dataPedido)).map(r => {
                const data = r.saidaData ? new Date(r.saidaData).toLocaleDateString('pt-PT',{day:'2-digit',month:'2-digit',year:'numeric'}) : '—';
                const pedido = r.dataPedido ? new Date(r.dataPedido).toLocaleDateString('pt-PT',{day:'2-digit',month:'long'}) : '—';
                const st = r.status || 'pendente';
                const cor = corStatus[st] || '#6B7280';
                const lbl = lblStatus[st] || st;
                const tel = (r.clienteTelefone||'').replace(/[^0-9]/g,'');

                return `
                <div style="background:white;border-radius:12px;border:1px solid #E5E7EB;margin-bottom:1rem;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.06);">
                    <div style="background:linear-gradient(135deg,#0A1628,#1565C0);padding:1rem 1.25rem;display:flex;justify-content:space-between;align-items:center;">
                        <div style="color:white;">
                            <div style="font-weight:700;">${r.saidaTitulo || 'Saída'}</div>
                            <div style="font-size:0.8rem;opacity:0.75;">${data} ${r.saidaHora ? 'às '+r.saidaHora : ''} · Porto: ${r.saidaPorto || '—'}</div>
                        </div>
                        <span style="background:${cor}22;color:${cor};border:1px solid ${cor};padding:0.3rem 0.75rem;border-radius:20px;font-size:0.8rem;font-weight:700;">${lbl}</span>
                    </div>
                    <div style="padding:1.25rem;">
                        <div style="display:grid;grid-template-columns:1fr 1fr;gap:0.75rem;margin-bottom:1rem;">
                            <div style="background:#F9FAFB;border-radius:8px;padding:0.75rem;">
                                <div style="font-size:0.75rem;color:#6B7280;margin-bottom:0.2rem;">Cliente</div>
                                <div style="font-weight:600;color:#0A1628;">${r.clienteNome || '—'}</div>
                                <div style="font-size:0.8rem;color:#6B7280;">${r.clienteEmail || ''}</div>
                            </div>
                            <div style="background:#F9FAFB;border-radius:8px;padding:0.75rem;">
                                <div style="font-size:0.75rem;color:#6B7280;margin-bottom:0.2rem;">Reserva</div>
                                <div style="font-weight:600;color:#0A1628;">${r.numPessoas} pessoa(s)</div>
                                <div style="font-size:0.8rem;color:#10B981;font-weight:600;">€${r.totalPagar}</div>
                            </div>
                        </div>
                        ${r.mensagem ? `<div style="background:#FFFBEB;border-left:3px solid #F59E0B;padding:0.75rem;border-radius:4px;font-size:0.85rem;color:#92400E;margin-bottom:1rem;"><i class="fas fa-comment"></i> "${r.mensagem}"</div>` : ''}
                        <div style="font-size:0.75rem;color:#9CA3AF;margin-bottom:0.75rem;">Pedido em: ${pedido}</div>
                        <div style="display:flex;gap:0.75rem;flex-wrap:wrap;">
                            ${tel ? `<a href="https://wa.me/351${tel}" target="_blank" style="display:inline-flex;align-items:center;gap:0.4rem;padding:0.6rem 1rem;background:#25D366;color:white;border-radius:8px;font-weight:600;font-size:0.85rem;text-decoration:none;"><i class="fab fa-whatsapp"></i> WhatsApp</a>` : ''}
                            ${st === 'pendente' ? `
                            <button onclick="acaoReservaCapitao(${r.id},'confirmada')" style="padding:0.6rem 1rem;background:#D1FAE5;color:#065F46;border:2px solid #10B981;border-radius:8px;cursor:pointer;font-weight:600;font-size:0.85rem;">
                                <i class="fas fa-check"></i> Confirmar
                            </button>
                            <button onclick="acaoReservaCapitao(${r.id},'cancelada')" style="padding:0.6rem 1rem;background:transparent;color:#EF4444;border:2px solid #EF4444;border-radius:8px;cursor:pointer;font-weight:600;font-size:0.85rem;">
                                <i class="fas fa-times"></i> Recusar
                            </button>
                            ` : ''}
                        </div>
                    </div>
                </div>`;
            }).join('');
        }

        function acaoReservaCapitao(id, novoStatus) {
            const acao = novoStatus === 'confirmada' ? 'confirmar' : 'recusar';
            if (!confirm(`Tem a certeza que deseja ${acao} esta reserva?`)) return;

            const reservas = JSON.parse(localStorage.getItem('reservasPendentes') || '[]');
            const idx = reservas.findIndex(r => r.id === id);
            if (idx === -1) return;

            reservas[idx].status = novoStatus;

            // Se confirmada: verificar se pode ativar saída partilhada
            if (novoStatus === 'confirmada') {
                const reserva = reservas[idx];
                const saidas = JSON.parse(localStorage.getItem('saidasData') || '[]');
                const saidaIdx = saidas.findIndex(s => s.id === reserva.saidaId);
                if (saidaIdx !== -1) {
                    const saida = saidas[saidaIdx];
                    const vagasRestantes = (saida.vagas || saida.lotacao || 0) - (reserva.numPessoas || 1);
                    // Propor partilha se a saída permite e há vagas restantes
                    if (saida.permitePartilha && vagasRestantes > 0 && !saida.partilhada) {
                        const ativarPartilha = confirm(
                            `✅ Reserva confirmada!

🤝 Esta saída permite partilha e ainda tem ${vagasRestantes} vaga(s) disponíveis.

Deseja ATIVAR a Saída Partilhada?
(A saída ficará visível com destaque especial e outros clientes poderão reservar os lugares restantes.)`
                        );
                        if (ativarPartilha) {
                            saidas[saidaIdx].partilhada = true;
                            saidas[saidaIdx].vagasPartilhadas = vagasRestantes;
                            localStorage.setItem('saidasData', JSON.stringify(saidas));
                            if (window.mostrarToast) mostrarToast('🤝 Saída partilhada ativada! Visível com destaque especial.', 'sucesso');
                        }
                    } else {
                        // Atualizar vagas na saída
                        if (saidaIdx !== -1) {
                            saidas[saidaIdx].vagasOcupadas = (saidas[saidaIdx].vagasOcupadas || 0) + (reserva.numPessoas || 1);
                            saidas[saidaIdx].vagas = Math.max(0, (saidas[saidaIdx].vagas || saidas[saidaIdx].lotacao || 0) - (reserva.numPessoas || 1));
                            localStorage.setItem('saidasData', JSON.stringify(saidas));
                        }
                    }
                }
                if (window.mostrarToast) mostrarToast('✅ Reserva confirmada!', 'sucesso');
            } else {
                if (window.mostrarToast) mostrarToast('Reserva recusada.', 'aviso');
            }

            localStorage.setItem('reservasPendentes', JSON.stringify(reservas));
            carregarReservas();
        }

        // Manter funções de compatibilidade
        function confirmarReserva(id) { acaoReservaCapitao(id, 'confirmada'); }
        function recusarReserva(id) { acaoReservaCapitao(id, 'cancelada'); }
        function contactarWhatsApp(tel, nome, dias) {
            const t = tel.replace(/[^0-9]/g,'');
            window.open(`https://wa.me/${t}?text=${encodeURIComponent('Olá '+nome+'! Confirmo a sua reserva de pesca. ')}`, '_blank');
        }

