            if (!usuarioStr) return;
            const capitao = JSON.parse(usuarioStr);

            const todasSaidas = JSON.parse(localStorage.getItem('saidasData') || '[]');
            const minhasSaidas = todasSaidas.filter(s => s.capitaoEmail === capitao.email && s.status !== 'cancelada');

            if (minhasSaidas.length === 0) {
                container.innerHTML = `
                    <div class="estado-vazio">
