                        <a href="criar-saida.html" class="btn btn-primario" style="margin-top: 1rem;">
                            <i class="fas fa-plus"></i> Criar Primeira Saída
                        </a>
                    </div>
                `;
                return;
            }

            // Ordenar por data (mais recentes primeiro)
            minhasSaidas.sort((a, b) => new Date(b.dataCriacao || b.data) - new Date(a.dataCriacao || a.data));

            const hoje = new Date();
            hoje.setHours(0, 0, 0, 0);

            container.innerHTML = `
                <div class="tabela-container">
                    <table class="tabela">
                        <thead>
                            <tr>
                                <th>Título</th>
                                <th>Barco</th>
                                <th>Duração</th>
                                <th>Porto</th>
                                <th>Temporada</th>
                                <th>Vagas</th>
                                <th>Preço</th>
                                <th>Estado</th>
                                <th>Ações</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${minhasSaidas.map(saida => {
                                // Usar temporada em vez de data fixa
                                const hoje2 = new Date();
                                hoje2.setHours(0,0,0,0);
                                // Verificar se saída está "passada" (só se temporadaFim existir e já passou)
                                const passada = saida.temporadaFim ? new Date(saida.temporadaFim) < hoje2 : false;
                                const vagas = saida.vagas !== undefined ? saida.vagas : saida.lotacao;
