            const usuarioStr = localStorage.getItem('usuarioLogado');
            if (!usuarioStr) return;
            const capitao = JSON.parse(usuarioStr);

            // Verificar reservas recentes (últimos 7 dias)
            const reservas = JSON.parse(localStorage.getItem('reservasPendentes') || '[]');
            const barcos = JSON.parse(localStorage.getItem('barcos') || '[]').filter(b => b.capitaoEmail === capitao.email);
            const barcoIds = barcos.map(b => b.id);

            const seteDias = new Date();
            seteDias.setDate(seteDias.getDate() - 7);

            const notifs = [];

            // Barcos pendentes de aprovação
            barcos.filter(b => b.status === 'pendente').forEach(b => {
                notifs.push({
                    icon: 'fa-ship', cor: '#FF8F00',
                    titulo: 'Barco Aguarda Aprovação',
                    texto: 'O barco "' + b.nome + '" está pendente de validação pela administração.',
                    data: b.dataCriacao ? new Date(b.dataCriacao) : new Date()
                });
            });

            // Barcos aprovados recentemente
            barcos.filter(b => b.status === 'aprovado' && b.dataAprovacao && new Date(b.dataAprovacao) > seteDias).forEach(b => {
                notifs.push({
                    icon: 'fa-check-circle', cor: '#22C55E',
                    titulo: 'Barco Aprovado! ✅',
                    texto: 'O barco "' + b.nome + '" foi aprovado. Já pode criar saídas!',
                    data: new Date(b.dataAprovacao)
                });
            });

            // Reservas pendentes recentes
            reservas.filter(r => barcoIds.includes(r.barcoId || r.barco_id) && r.status === 'pendente').forEach(r => {
                const barco = barcos.find(b => b.id == (r.barcoId || r.barco_id));
                notifs.push({
                    icon: 'fa-envelope', cor: 'var(--cor-secundaria)',
                    titulo: 'Novo Pedido de Reserva',
                    texto: 'Pedido para o barco ' + (barco ? barco.nome : '') + ' em ' + (r.data || '--'),
                    data: r.dataCriacao ? new Date(r.dataCriacao) : new Date()
                });
            });

            // Ordenar por data (mais recentes primeiro)
            notifs.sort((a, b) => b.data - a.data);

            if (notifs.length === 0) {
                container.innerHTML = `
                    <div style="text-align:center; padding:2rem; color:rgba(245,245,245,0.4);">
                        <i class="fas fa-bell-slash" style="font-size:2.5rem; margin-bottom:1rem; display:block;"></i>
                        <p>Sem notificações de momento.</p>
                        <small>As notificações aparecerão aqui quando houver actividade.</small>
                    </div>
                `;
                return;
            }

            container.innerHTML = '<div class="notificacoes-lista">' +
                notifs.slice(0, 5).map(n => {
                    const dataFormatada = n.data.toLocaleDateString('pt-PT', {day:'2-digit', month:'2-digit', year:'numeric'});
                    return `
                        <div class="notificacao-item">
                            <div class="notificacao-icon" style="background-color: ${n.cor}20; border: 1px solid ${n.cor}40;">
                                <i class="fas ${n.icon}" style="color:${n.cor};"></i>
                            </div>
                            <div class="notificacao-conteudo">
                                <div class="notificacao-titulo">${n.titulo}</div>
                                <div class="notificacao-texto">${n.texto}</div>
                                <div class="notificacao-data">${dataFormatada}</div>
                            </div>
                        </div>
                    `;
                }).join('') + '</div>';
        }

