        function carregarPerfilCapitao() {
            const usuarioStr = localStorage.getItem('usuarioLogado');
            if (!usuarioStr) return;

            const capitao = JSON.parse(usuarioStr);

            document.getElementById('capitaoPerfilNome').value = capitao.nome || '';
            document.getElementById('capitaoPerfilEmail').value = capitao.email || '';
            document.getElementById('capitaoPerfilTelefone').value = capitao.telefone || '';
            document.getElementById('capitaoPerfilMorada').value = capitao.morada || '';
            document.getElementById('capitaoPerfilCidade').value = capitao.cidade || '';
            document.getElementById('capitaoPerfilCodigoPostal').value = capitao.codigoPostal || '';
            document.getElementById('capitaoPerfilLicenca').value = capitao.licencaMaritima || '';
            document.getElementById('capitaoPerfilExperiencia').value = capitao.experiencia || '';
            document.getElementById('capitaoPerfilPorto').value = capitao.porto || '';
            document.getElementById('capitaoPerfilNIF').value = capitao.nif || '';
            document.getElementById('capitaoPerfilBio').value = capitao.biografia || '';
        }

        // Carregar perfil quando abrir a seção
        menuItems.forEach(item => {
            item.addEventListener('click', (e) => {
                if (item.dataset.section === 'perfil') {
                    setTimeout(carregarPerfilCapitao, 100);
                }
            });
        });

        // Salvar perfil
        document.getElementById('formEditarPerfilCapitao').addEventListener('submit', (e) => {
            e.preventDefault();

            const usuarioStr = localStorage.getItem('usuarioLogado');
            if (!usuarioStr) return;

            const capitao = JSON.parse(usuarioStr);

            // Atualizar dados
            capitao.nome = document.getElementById('capitaoPerfilNome').value;
            capitao.telefone = document.getElementById('capitaoPerfilTelefone').value;
            capitao.morada = document.getElementById('capitaoPerfilMorada').value;
            capitao.cidade = document.getElementById('capitaoPerfilCidade').value;
            capitao.codigoPostal = document.getElementById('capitaoPerfilCodigoPostal').value;
            capitao.licencaMaritima = document.getElementById('capitaoPerfilLicenca').value;
            capitao.experiencia = parseInt(document.getElementById('capitaoPerfilExperiencia').value) || 0;
            capitao.porto = document.getElementById('capitaoPerfilPorto').value;
            capitao.nif = document.getElementById('capitaoPerfilNIF').value;
            capitao.biografia = document.getElementById('capitaoPerfilBio').value;

            // Salvar no localStorage
            localStorage.setItem('usuarioLogado', JSON.stringify(capitao));

            // Atualizar na lista de utilizadores
            let utilizadores = JSON.parse(localStorage.getItem('utilizadores') || '[]');
            const index = utilizadores.findIndex(u => u.id === capitao.id);
            if (index !== -1) {
                utilizadores[index] = capitao;
                localStorage.setItem('utilizadores', JSON.stringify(utilizadores));
            }

            // Atualizar nome na sidebar
            const sidebarNome = document.getElementById('sidebarNome');
            const sidebarAvatar = document.getElementById('sidebarAvatar');
            if (sidebarNome) sidebarNome.textContent = capitao.nome;
            if (sidebarAvatar) {
                const initials = capitao.nome.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();
                sidebarAvatar.textContent = initials;
            }

            mostrarToast('Perfil atualizado com sucesso!', 'sucesso');
        });

