        // ============================================
        // CONTACTAR VIA WHATSAPP
        // ============================================
        function contactarWhatsApp(telefone, nome, dias) {
            // Remover caracteres não numéricos
            const telefoneClean = telefone.replace(/[^0-9]/g, '');

            const mensagem = `Olá ${nome}! 👋

Recebi o seu pedido de reserva para os dias: ${dias}

Tenho disponibilidade! 🎣

Vamos combinar os detalhes da sua saída de pesca?

Fico a aguardar o seu contacto!

Cumprimentos,
Algarve Tuna Charter ⚓`;

            const url = `https://wa.me/${telefoneClean}?text=${encodeURIComponent(mensagem)}`;
            window.open(url, '_blank');
        }

        // ============================================
        // CONFIRMAR/RECUSAR RESERVA
        // ============================================
        function confirmarReserva(reservaId) {
            if (!confirm('Confirmar esta reserva?')) return;

            let reservas = JSON.parse(localStorage.getItem('reservas') || '[]');
            const index = reservas.findIndex(r => r.id === reservaId);

            if (index !== -1) {
                reservas[index].status = 'confirmada';
                localStorage.setItem('reservas', JSON.stringify(reservas));
                mostrarToast('✅ Reserva confirmada!', 'sucesso');
                carregarReservas();
            }
        }

        function recusarReserva(reservaId) {
            if (!confirm('Recusar esta reserva? Esta ação não pode ser desfeita.')) return;

            let reservas = JSON.parse(localStorage.getItem('reservas') || '[]');
            const index = reservas.findIndex(r => r.id === reservaId);

            if (index !== -1) {
                reservas[index].status = 'recusada';
                localStorage.setItem('reservas', JSON.stringify(reservas));
                mostrarToast('Reserva recusada', 'aviso');
                carregarReservas();
            }
        }

        function logout() {
            if (confirm('Tem a certeza que deseja sair?')) {
                window.location.href = 'index.html';
            }
        }




